# Phase 2/3 보고서 인덱스 + 매니페스트 생성기 (docs/reports.html + docs/reports-manifest.json)
"""Scan docs/phase2/ and docs/phase3/ for autogenerated reports, then
emit a discovery page and a machine-readable manifest.

Outputs:
  - docs/reports.html              # human-readable listing (bilingual)
  - docs/reports-manifest.json     # machine-readable, consumed by docs/index.html

Phase 2 reports live at docs/phase2/<host-slug>.html and cover one host
each. Phase 3 reports live at docs/phase3/<planet-slug>.html and cover
one planet. Host ↔ planet pairing is inferred by slug prefix
(``trappist-1-d`` belongs to host ``trappist-1``); display names come
from the DB so the table shows ``TRAPPIST-1`` rather than ``trappist-1``.

Usage:
    python3 scripts/pipeline/build_reports_index.py
"""

from __future__ import annotations

import json
import re
import sys
from pathlib import Path


def to_url_slug(name: str) -> str:
    s = name.lower()
    s = re.sub(r'[^a-z0-9]+', '-', s)
    return s.strip('-')


def load_db_names(repo: Path) -> tuple[dict[str, str], dict[str, tuple[str, str]]]:
    """Return ({host_slug: host_display_name}, {planet_slug: (host_slug, planet_letter)}).

    The host display name comes from stellar_props_curated keys.
    Planet letter is the suffix after the host slug.
    """
    stellar = json.loads((repo / 'db' / 'stellar_props_curated.json').read_text())
    planets = json.loads((repo / 'db' / 'planets_curated.json').read_text())

    host_names: dict[str, str] = {}
    for host_name in stellar:
        host_names[to_url_slug(host_name)] = host_name
    # planets_curated keys are host names; the planet name is in each entry.
    planet_map: dict[str, tuple[str, str]] = {}
    for host_name, entries in planets.items():
        host_slug = to_url_slug(host_name)
        host_names.setdefault(host_slug, host_name)
        for entry in entries:
            pname = entry.get('pl_name')
            if not pname: continue
            psl = to_url_slug(pname)
            # planet letter: the bit after the host slug + '-'
            letter = psl[len(host_slug) + 1:] if psl.startswith(host_slug + '-') else psl
            planet_map[psl] = (host_slug, letter)
    return host_names, planet_map


def scan_reports(repo: Path):
    """Walk docs/phase2/ and docs/phase3/ for per-planet/per-host .html, returning slugs.

    Skip infrastructure pages — underscore-prefixed (e.g. ``_demo-hex-viz``)
    and the manual-fetch index — since those aren't per-planet reports.
    """
    phase2_dir = repo / 'docs' / 'phase2'
    phase3_dir = repo / 'docs' / 'phase3'
    skip = {'manual-fetch'}

    def is_report(p: Path) -> bool:
        return not p.stem.startswith('_') and p.stem not in skip

    phase2_slugs = sorted(p.stem for p in phase2_dir.glob('*.html') if is_report(p)) if phase2_dir.exists() else []
    phase3_slugs = sorted(p.stem for p in phase3_dir.glob('*.html') if is_report(p)) if phase3_dir.exists() else []
    return phase2_slugs, phase3_slugs


def build_manifest(host_names, planet_map, phase2_slugs, phase3_slugs):
    """Group by host. Returns {host_display_name: {phase2: path?, phase3: {letter: path}}}."""
    manifest: dict[str, dict] = {}

    for slug in phase2_slugs:
        host = host_names.get(slug, slug)
        manifest.setdefault(host, {'phase2': None, 'phase3': {}})
        manifest[host]['phase2'] = f'phase2/{slug}.html'

    for slug in phase3_slugs:
        if slug in planet_map:
            host_slug, letter = planet_map[slug]
        elif slug in host_names:
            # star-level synthesis (slug matches a host name exactly).
            # 별 자체에 대한 합성 문서. 시스템 그룹 안에서 ★ letter 로 정렬.
            host_slug, letter = slug, '★'
        else:
            # fall back to last-token split
            parts = slug.rsplit('-', 1)
            host_slug, letter = (parts[0], parts[1]) if len(parts) == 2 else (slug, '?')
        host = host_names.get(host_slug, host_slug)
        manifest.setdefault(host, {'phase2': None, 'phase3': {}})
        manifest[host]['phase3'][letter] = f'phase3/{slug}.html'

    return manifest


