def render_html(manifest: dict, has_manual_fetch: bool) -> str:
    if not manifest:
        rows = '<tr><td colspan="3" class="empty">No reports yet.</td></tr>'
    else:
        row_parts = []
        for host_name, info in sorted(manifest.items()):
            p2_cell = (
                f'<a href="{info["phase2"]}"><span class="pill pill-p2">P2</span> view</a>'
                if info.get('phase2') else '<span class="empty">—</span>'
            )
            p3_letters = info.get('phase3', {})
            if p3_letters:
                links = []
                for letter, path in sorted(p3_letters.items()):
                    links.append(f'<a href="{path}"><span class="pill pill-p3">P3</span> {letter}</a>')
                p3_cell = ' &nbsp; '.join(links)
            else:
                p3_cell = '<span class="empty">—</span>'
            row_parts.append(
                f'        <tr>\n'
                f'          <td class="sys" data-label="System">{host_name}</td>\n'
                f'          <td data-label="Phase 2">{p2_cell}</td>\n'
                f'          <td data-label="Phase 3">{p3_cell}</td>\n'
                f'        </tr>'
            )
        rows = '\n'.join(row_parts)

    sidepanels = ''
    if has_manual_fetch:
        sidepanels = (
            '  <div class="sidepanel">\n'
            '    <span class="pill pill-mf">MF</span>\n'
            '    <a href="phase3/manual-fetch.html" data-i18n="mf_link"></a>\n'
            '    <span class="note" data-i18n="mf_note"></span>\n'
            '  </div>'
        )

    return PAGE_TEMPLATE.replace('__ROWS__', rows).replace('__SIDEPANELS__', sidepanels)


def main() -> int:
    here = Path(__file__).resolve()
    repo = here.parent.parent.parent

    host_names, planet_map = load_db_names(repo)
    phase2_slugs, phase3_slugs = scan_reports(repo)
    manifest = build_manifest(host_names, planet_map, phase2_slugs, phase3_slugs)

    has_manual_fetch = (repo / 'docs' / 'phase3' / 'manual-fetch.html').exists()

    out_html = repo / 'docs' / 'reports.html'
    out_html.write_text(render_html(manifest, has_manual_fetch), encoding='utf-8')

    out_json = repo / 'docs' / 'reports-manifest.json'
    out_json.write_text(json.dumps(manifest, ensure_ascii=False, indent=2), encoding='utf-8')

    print(f'wrote {out_html.relative_to(repo)}')
    print(f'wrote {out_json.relative_to(repo)}')
    print(f'hosts: {len(manifest)}  '
          f'p2 reports: {sum(1 for v in manifest.values() if v.get("phase2"))}  '
          f'p3 reports: {sum(len(v.get("phase3", {})) for v in manifest.values())}')
    return 0


if __name__ == '__main__':
    sys.exit(main())
